response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=1024,
    messages=[{
        "role": "user",
        "content": "Extraé el nombre y el email de: Juan Pérez, juan@email.com",
    }],
    output_config={
        "format": {
            "type": "json_schema",
            "schema": {
                "type": "object",
                "properties": {
                    "name": {"type": "string"},
                    "email": {"type": "string"},
                },
                "required": ["name", "email"],
                "additionalProperties": False,
            },
        }
    },
)
# response.content[0].text es JSON válido garantizado, listo para json.loads()
import json
datos = json.loads(response.content[0].text)
print(datos["name"])   # "Juan Pérez"
print(datos["email"])  # "juan@email.com"
